mapper.select:
select * from ( select msg.id, msg.conversation_id, msg.sender_id, coalesce(m.member_nickname, m.member_name) as sender_name, m.member_handle as sender_handle, msg.content, msg.is_deleted, case when msg.sender_id = #{memberId} and coalesce(v.partner_last_read, 0) >= msg.id then true else false end as read_by_partner, msg.created_datetime, msg.updated_datetime, f.id as file_id, f.original_name as file_original_name, f.file_path as file_path, f.file_size as file_size, f.content_type as file_content_type from tbl_message msg join tbl_member m on m.id = msg.sender_id join v_my_chat v on v.conversation_id = msg.conversation_id and v.member_id = #{memberId} left join tbl_message_deletion md on md.message_id = msg.id and md.member_id = #{memberId} left join tbl_chat_file cf on cf.message_id = msg.id left join tbl_file f on f.id = cf.id where msg.conversation_id = #{conversationId} and msg.is_deleted = false and md.message_id is null and msg.id > coalesce( (select deleted_after_message_id from tbl_conversation_setting where conversation_id = #{conversationId} and member_id = #{memberId}), 0 ) and not ( msg.sender_id != #{memberId} and exists ( select 1 from tbl_conversation_setting cs_block where cs_block.conversation_id = #{conversationId} and cs_block.member_id = #{memberId} and cs_block.blocked_after_message_id is not null and msg.id > cs_block.blocked_after_message_id and (cs_block.block_released_message_id is null or msg.id <= cs_block.block_released_message_id) ) )
and msg.id < #{cursor}
order by msg.id desc limit #{pageSize} ) sub order by sub.id asc

mapper.update:
update tbl_message
set is_deleted = true, updated_datetime = now()
where conversation_id = #{conversationId}
  and is_deleted = false
  and created_datetime >= #{activatedAt}
  and created_datetime <= #{expiresAt}

update tbl_conversation_setting
set disappear_message = 'none',
    disappear_activated_at = null,
    updated_datetime = now()
where conversation_id = #{conversationId}
  and member_id = #{memberId}
